package com.izonehub.stores.project;
import com.izonehub.stores.common.BaseEntity;import com.izonehub.stores.store.Store;import jakarta.persistence.*;import java.math.BigDecimal;
@Entity public class Project extends BaseEntity{@Column(nullable=false,unique=true) private String code;@Column(nullable=false) private String name;@ManyToOne(optional=false,fetch=FetchType.LAZY) private Store siteStore;@Column(precision=19,scale=4) private BigDecimal budgetCeiling;@Column(nullable=false) private boolean active=true;protected Project(){} public Project(String code,String name,Store siteStore,BigDecimal budgetCeiling){this.code=code;this.name=name;this.siteStore=siteStore;this.budgetCeiling=budgetCeiling;} public String getCode(){return code;} public boolean isActive(){return active;} public void close(){active=false;}}
